use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF file
sub extract_text {
    my ($pdf_file) = @_;

    # Load the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Initialize an array to hold text
    my @text = ();

    # Loop through each page in the PDF
    for (my $page_num = 1; $page_num <= $pdf->pages; $page_num++) {
        my $page = $pdf->page($page_num);

        # Extract text from the page
        my $text = $page->text;

        # Unidecode for handling non-ASCII characters
        my $decoded_text = unidecode($text);

        # Append the text to the array
        push @text, $decoded_text;
    }

    return join("\n", @text);
}

